/* \u8A2D\u5B9A\u30CF\u30D6: \u5DE6\u30CA\u30D3 + \u53F3\u30DA\u30A4\u30F3 (Spira \u306E\u8A2D\u5B9A\u30CF\u30D6\u3068\u540C\u3058\u4F5C\u308A) */
